SELECT * FROM wx_group_info
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM wx_group_info g
WHERE EXISTS (
    SELECT 1
    FROM wx_user_info u
    WHERE u.user_id = g.create_user_id
      AND u.uuid = #{uuid}
      AND u.is_del = 0
)
ORDER BY g.create_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM wx_group_info g
WHERE g.corp_id IN

    #{corpId}


    AND EXISTS (
        SELECT 1
        FROM wx_user_info u
        WHERE u.user_id = g.create_user_id
          AND u.uuid = #{uuid}
          AND u.is_del = 0
    )

ORDER BY g.create_time DESC
LIMIT #{offset}, #{limit}
